//! Terminal prosody pressure for finite decode horizons.
//!
//! Mirrors the TypeScript controller in `@a0n/aether/terminal-prosody`.
//! The runtime cannot infer punctuation without tokenizer metadata, so callers
//! provide token-id sets for sentence-close and stop roles.

pub const PHI_MILLI: u64 = 1618;
pub const REYNOLDS_CRITICAL_MILLI: u64 = 2300;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TerminalTailState {
    OpenClause,
    SentenceClosed,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TerminalTokenRole {
    Continuation,
    SentenceClose,
    Stop,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TerminalWrapDirective {
    Continue,
    ChooseSentenceClose,
    ChooseStop,
}

#[derive(Clone, Copy, Debug, PartialEq)]
pub struct TerminalProsodyPressure {
    pub emitted_tokens: usize,
    pub max_tokens: usize,
    pub remaining_tokens: usize,
    pub pressure: u64,
    pub threshold: u64,
    pub crossed_break: bool,
    pub ratio: f32,
    pub directive: TerminalWrapDirective,
}

#[derive(Clone, Copy, Debug)]
pub struct TerminalProsodyContext<'a> {
    /// One-based candidate count: the token being selected is counted here.
    pub emitted_tokens: usize,
    pub max_tokens: usize,
    pub tail_state: TerminalTailState,
    pub sentence_close_token_ids: &'a [u32],
    pub stop_token_ids: &'a [u32],
    pub preferred_bias: f32,
    pub secondary_bias: f32,
    pub continuation_penalty: f32,
    pub defer_stop_until_sentence_closed: bool,
}

impl<'a> TerminalProsodyContext<'a> {
    pub fn new(
        emitted_tokens: usize,
        max_tokens: usize,
        tail_state: TerminalTailState,
        sentence_close_token_ids: &'a [u32],
        stop_token_ids: &'a [u32],
    ) -> Self {
        Self {
            emitted_tokens,
            max_tokens,
            tail_state,
            sentence_close_token_ids,
            stop_token_ids,
            preferred_bias: 4.0,
            secondary_bias: 1.0,
            continuation_penalty: 2.0,
            defer_stop_until_sentence_closed: true,
        }
    }
}

#[derive(Clone, Copy, Debug, PartialEq)]
pub struct TerminalTokenSelection {
    pub token_id: u32,
    pub baseline_token_id: u32,
    pub pressure: TerminalProsodyPressure,
    pub adjusted: bool,
    pub stop_deferred: bool,
}

pub fn terminal_remaining_tokens(emitted_tokens: usize, max_tokens: usize) -> usize {
    max_tokens.saturating_sub(emitted_tokens)
}

pub fn terminal_wrap_pressure(emitted_tokens: usize) -> u64 {
    (emitted_tokens as u64 + 1) * REYNOLDS_CRITICAL_MILLI
}

pub fn terminal_wrap_threshold(emitted_tokens: usize, max_tokens: usize) -> u64 {
    (terminal_remaining_tokens(emitted_tokens, max_tokens) as u64 + 1) * PHI_MILLI
}

pub fn terminal_wrap_directive(
    emitted_tokens: usize,
    max_tokens: usize,
    tail_state: TerminalTailState,
) -> TerminalWrapDirective {
    let pressure = terminal_wrap_pressure(emitted_tokens);
    let threshold = terminal_wrap_threshold(emitted_tokens, max_tokens);
    if pressure < threshold {
        TerminalWrapDirective::Continue
    } else if tail_state == TerminalTailState::SentenceClosed {
        TerminalWrapDirective::ChooseStop
    } else {
        TerminalWrapDirective::ChooseSentenceClose
    }
}

pub fn measure_terminal_prosody(context: &TerminalProsodyContext<'_>) -> TerminalProsodyPressure {
    let remaining_tokens = terminal_remaining_tokens(context.emitted_tokens, context.max_tokens);
    let pressure = terminal_wrap_pressure(context.emitted_tokens);
    let threshold = terminal_wrap_threshold(context.emitted_tokens, context.max_tokens);
    let crossed_break = pressure >= threshold;
    TerminalProsodyPressure {
        emitted_tokens: context.emitted_tokens,
        max_tokens: context.max_tokens,
        remaining_tokens,
        pressure,
        threshold,
        crossed_break,
        ratio: if threshold > 0 {
            pressure as f32 / threshold as f32
        } else {
            f32::INFINITY
        },
        directive: terminal_wrap_directive(
            context.emitted_tokens,
            context.max_tokens,
            context.tail_state,
        ),
    }
}

pub fn classify_terminal_token(
    token_id: u32,
    sentence_close_token_ids: &[u32],
    stop_token_ids: &[u32],
) -> TerminalTokenRole {
    if stop_token_ids.contains(&token_id) {
        TerminalTokenRole::Stop
    } else if sentence_close_token_ids.contains(&token_id) {
        TerminalTokenRole::SentenceClose
    } else {
        TerminalTokenRole::Continuation
    }
}

pub fn observe_terminal_tail_state(
    token_id: u32,
    sentence_close_token_ids: &[u32],
    stop_token_ids: &[u32],
) -> TerminalTailState {
    match classify_terminal_token(token_id, sentence_close_token_ids, stop_token_ids) {
        TerminalTokenRole::SentenceClose | TerminalTokenRole::Stop => {
            TerminalTailState::SentenceClosed
        }
        TerminalTokenRole::Continuation => TerminalTailState::OpenClause,
    }
}

pub fn select_terminal_token(
    logits: &[f32],
    context: &TerminalProsodyContext<'_>,
) -> TerminalTokenSelection {
    let (baseline_token_id, baseline_logit) = argmax_finite(logits).unwrap_or((0, 0.0));
    let pressure = measure_terminal_prosody(context);
    if !pressure.crossed_break {
        return TerminalTokenSelection {
            token_id: baseline_token_id,
            baseline_token_id,
            pressure,
            adjusted: false,
            stop_deferred: false,
        };
    }

    let has_sentence_close_candidate = context.sentence_close_token_ids.iter().any(|&token_id| {
        logits.get(token_id as usize).is_some_and(|v| v.is_finite())
            && classify_terminal_token(
                token_id,
                context.sentence_close_token_ids,
                context.stop_token_ids,
            ) == TerminalTokenRole::SentenceClose
    });
    let should_defer_stop = context.defer_stop_until_sentence_closed
        && pressure.directive == TerminalWrapDirective::ChooseSentenceClose
        && has_sentence_close_candidate;

    let mut best_token = baseline_token_id;
    let mut best_score = f32::NEG_INFINITY;
    for (token_id, &logit) in logits.iter().enumerate() {
        if !logit.is_finite() {
            continue;
        }
        let token_id = token_id as u32;
        let role = classify_terminal_token(
            token_id,
            context.sentence_close_token_ids,
            context.stop_token_ids,
        );
        if should_defer_stop && role == TerminalTokenRole::Stop {
            continue;
        }
        let score = logit + role_bias(role, pressure.directive, context, pressure.ratio);
        if score > best_score {
            best_score = score;
            best_token = token_id;
        }
    }

    TerminalTokenSelection {
        token_id: best_token,
        baseline_token_id,
        pressure,
        adjusted: best_token != baseline_token_id
            || (best_score - baseline_logit).abs() > f32::EPSILON,
        stop_deferred: should_defer_stop,
    }
}

fn argmax_finite(logits: &[f32]) -> Option<(u32, f32)> {
    let mut best: Option<(u32, f32)> = None;
    for (token_id, &logit) in logits.iter().enumerate() {
        if !logit.is_finite() {
            continue;
        }
        if best.is_none_or(|(_, best_logit)| logit > best_logit) {
            best = Some((token_id as u32, logit));
        }
    }
    best
}

fn role_bias(
    role: TerminalTokenRole,
    directive: TerminalWrapDirective,
    context: &TerminalProsodyContext<'_>,
    ratio: f32,
) -> f32 {
    if directive == TerminalWrapDirective::Continue {
        return 0.0;
    }
    let strength = ratio.clamp(1.0, 2.618);
    let preferred_bias = context.preferred_bias * strength;
    let secondary_bias = context.secondary_bias * strength;
    let continuation_penalty = context.continuation_penalty * strength;
    match directive {
        TerminalWrapDirective::Continue => 0.0,
        TerminalWrapDirective::ChooseSentenceClose => match role {
            TerminalTokenRole::SentenceClose => preferred_bias,
            TerminalTokenRole::Stop => secondary_bias,
            TerminalTokenRole::Continuation => -continuation_penalty,
        },
        TerminalWrapDirective::ChooseStop => match role {
            TerminalTokenRole::Stop => preferred_bias,
            TerminalTokenRole::SentenceClose => secondary_bias,
            TerminalTokenRole::Continuation => -continuation_penalty,
        },
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn reynolds_phi_break_crosses_near_horizon_end() {
        let before = TerminalProsodyContext::new(0, 8, TerminalTailState::OpenClause, &[4], &[2]);
        assert!(!measure_terminal_prosody(&before).crossed_break);

        let after = TerminalProsodyContext::new(4, 8, TerminalTailState::OpenClause, &[4], &[2]);
        let pressure = measure_terminal_prosody(&after);
        assert!(pressure.crossed_break);
        assert_eq!(
            pressure.directive,
            TerminalWrapDirective::ChooseSentenceClose
        );
    }

    #[test]
    fn pressure_fields_match_finite_model() {
        let context = TerminalProsodyContext::new(4, 8, TerminalTailState::OpenClause, &[4], &[2]);
        let pressure = measure_terminal_prosody(&context);
        assert_eq!(pressure.emitted_tokens, 4);
        assert_eq!(pressure.max_tokens, 8);
        assert_eq!(pressure.remaining_tokens, 4);
        assert_eq!(pressure.pressure, 11_500);
        assert_eq!(pressure.threshold, 8_090);
        assert!(pressure.crossed_break);
        assert_eq!(
            pressure.directive,
            TerminalWrapDirective::ChooseSentenceClose
        );
    }

    #[test]
    fn pre_break_keeps_baseline_argmax() {
        let logits = [0.0, 0.0, 3.0, 5.0, 2.0];
        let context = TerminalProsodyContext::new(0, 8, TerminalTailState::OpenClause, &[4], &[2]);
        let selection = select_terminal_token(&logits, &context);
        assert_eq!(selection.baseline_token_id, 3);
        assert_eq!(selection.token_id, 3);
        assert!(!selection.adjusted);
        assert!(!selection.stop_deferred);
    }

    #[test]
    fn open_clause_prefers_sentence_close_over_baseline_continuation() {
        let logits = [0.0, 0.0, 3.0, 5.0, 2.0];
        let context = TerminalProsodyContext::new(1, 1, TerminalTailState::OpenClause, &[4], &[2]);
        let selection = select_terminal_token(&logits, &context);
        assert_eq!(selection.baseline_token_id, 3);
        assert_eq!(selection.token_id, 4);
        assert!(selection.adjusted);
    }

    #[test]
    fn open_clause_defers_stop_when_close_candidate_is_visible() {
        let logits = [0.0, 0.0, 6.0, 1.0, 2.0];
        let context = TerminalProsodyContext::new(1, 1, TerminalTailState::OpenClause, &[4], &[2]);
        let selection = select_terminal_token(&logits, &context);
        assert_eq!(selection.baseline_token_id, 2);
        assert_eq!(selection.token_id, 4);
        assert!(selection.stop_deferred);
    }

    #[test]
    fn open_clause_allows_stop_when_no_close_candidate_is_visible() {
        let logits = [0.0, 0.0, 6.0, 1.0, 2.0];
        let context = TerminalProsodyContext::new(1, 1, TerminalTailState::OpenClause, &[9], &[2]);
        let selection = select_terminal_token(&logits, &context);
        assert_eq!(selection.baseline_token_id, 2);
        assert_eq!(selection.token_id, 2);
        assert!(!selection.stop_deferred);
    }

    #[test]
    fn overlapping_stop_and_close_id_does_not_create_phantom_close_candidate() {
        let logits = [0.0, 0.0, 6.0, 1.0, 2.0];
        let context = TerminalProsodyContext::new(1, 1, TerminalTailState::OpenClause, &[2], &[2]);
        let selection = select_terminal_token(&logits, &context);
        assert_eq!(
            classify_terminal_token(2, &[2], &[2]),
            TerminalTokenRole::Stop
        );
        assert_eq!(selection.baseline_token_id, 2);
        assert_eq!(selection.token_id, 2);
        assert!(!selection.stop_deferred);
    }

    #[test]
    fn closed_sentence_prefers_stop() {
        let logits = [0.0, 0.0, 2.0, 5.0, 3.0];
        let context =
            TerminalProsodyContext::new(1, 1, TerminalTailState::SentenceClosed, &[4], &[2]);
        let selection = select_terminal_token(&logits, &context);
        assert_eq!(selection.token_id, 2);
    }
}
